&lt;td class=&quot;tableblock halign-left valign-top&quot;&gt;&lt;p class=&quot;tableblock&quot;&gt;Bloc &lt;code&gt;java { sourceCompatibility = JavaVersion.VERSION_21 }&lt;/code&gt;&lt;/p&gt;&lt;/td&gt;
