&lt;td class=&quot;tableblock halign-left valign-top&quot;&gt;&lt;p class=&quot;tableblock&quot;&gt;Dépendance implicite &lt;code&gt;compileKotlin&lt;/code&gt; → &lt;code&gt;openApiGenerate&lt;/code&gt;&lt;/p&gt;&lt;/td&gt;
&lt;td class=&quot;tableblock halign-left valign-top&quot;&gt;&lt;p class=&quot;tableblock&quot;&gt;&lt;code&gt;afterEvaluate { tasks.named(&quot;compileKotlin&quot;).dependsOn(&quot;openApiGenerate&quot;) }&lt;/code&gt;&lt;/p&gt;&lt;/td&gt;
