&lt;li&gt;&lt;a href=&quot;#règles_de_rendu&quot;&gt;4.3. Règles de rendu&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;a href=&quot;#étape_3_utilisation_au_quotidien&quot;&gt;5. Étape 3 : Utilisation au quotidien&lt;/a&gt;
&lt;ul class=&quot;sectlevel2&quot;&gt;
&lt;li&gt;&lt;a href=&quot;#diagramme_complet&quot;&gt;5.1. Diagramme complet&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&quot;#filtrer_par_communauté&quot;&gt;5.2. Filtrer par communauté&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&quot;#filtrer_par_type_darête&quot;&gt;5.3. Filtrer par type d&amp;#8217;arête&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&quot;#filtrer_par_type_de_noeud_et_confiance&quot;&gt;5.4. Filtrer par type de noeud et confiance&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&quot;#répertoire_de_sortie_personnalisé&quot;&gt;5.5. Répertoire de sortie personnalisé&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&quot;#référence_complète_des_propriétés&quot;&gt;5.6. Référence complète des propriétés&lt;/a&gt;&lt;/li&gt;
