&lt;li&gt;&lt;a href=&quot;#mise_à_jour_incrémentale&quot;&gt;6.3. Mise à jour incrémentale&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;a href=&quot;#le_dogfooding_le_plugin_se_documente_lui_même&quot;&gt;7. Le dogfooding : le plugin se documente lui-même&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&quot;#pourquoi_cest_déterministe_et_pourquoi_ça_compte&quot;&gt;8. Pourquoi c&amp;#8217;est déterministe (et pourquoi ça compte)&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&quot;#diagrammes_du_pipeline_lui_même&quot;&gt;9. Diagrammes du pipeline lui-même&lt;/a&gt;&lt;/li&gt;
