&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;a href=&quot;#_permissionauthorization&quot;&gt;2. Permission(authorization)&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&quot;#_recherche_de_fichiers&quot;&gt;3. Recherche de fichiers&lt;/a&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
