&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_permissionauthorization&quot;&gt;2. Permission(authorization)&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;CHMOD est utilisé pour changer les permissions d&amp;#8217;un fichier.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre&gt;PERMISSION      COMMAND

U   G   W
rwx rwx rwx     chmod 777 filename
rwx rwx r-x     chmod 775 filename
rwx r-x r-x     chmod 755 filename
rw- rw- r--     chmod 664 filename
rw- r-- r--     chmod 644 filename

U = User
G = Group
W = World

r = Readable
w = writable
x = executable
- = no permission&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Une autre facon de voir les permissions:&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre&gt;400     read by owner
040     read by group
004     read by anybody (other)
200     write by owner
020     write by group
002     write by anybody
100     execute by owner
010     execute by group
001     execute by anybody&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Pour obtenir une combinaison, il suffit de les additionner.&lt;br&gt;
Par exemple, pour être lu, écrit, exécuté par le propriétaire,&lt;br&gt;
lu, exécuté, par groupe et exécuté par n&amp;#8217;importe qui,&lt;br&gt;
vous ajouteriez 400+200+100+040+010+001 pour donner 751.&lt;br&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_recherche_de_fichiers&quot;&gt;3. &lt;a href=&quot;/blog/2024/0074_seach_file_linux_post.html&quot;&gt;Recherche de fichiers&lt;/a&gt;&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;

&lt;/div&gt;
&lt;/div&gt;

&lt;div class=&quot;paragraph&quot;&gt;
&lt;div class=&quot;title&quot;&gt;La problématique :&lt;/div&gt;
&lt;p&gt;Comment exposer le port 8820 du sous système ubuntu dont l&amp;#8217;hôte est windows ?
Ubuntu est amorcé par la commande &lt;code&gt;wsl --install&lt;/code&gt;.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;div class=&quot;title&quot;&gt;Réference :&lt;/div&gt;
&lt;p&gt;&lt;a href=&quot;https://www.it-connect.fr/wsl-2-port-forwarding-comment-acceder-a-sa-machine-virtuelle-a-distance/&quot;&gt;wsl-2-port-forwarding&lt;/a&gt;&lt;/p&gt;
&lt;/div&gt;

&lt;div id=&quot;preamble&quot;&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;div class=&quot;title&quot;&gt;&lt;em&gt;Temps de lecture : 3 min&lt;/em&gt;&lt;/div&gt;
&lt;p&gt;Pandoc un convertisseur universel de document&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Pandoc est un logiciel de traitement de texte open source qui peut être utilisé pour convertir des documents entre différents formats.
Il existe plusieurs façons d&amp;#8217;installer Pandoc.&lt;/p&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_installation_à_partir_de_la_page_de_téléchargement&quot;&gt;&lt;strong&gt;Installation à partir de la page de téléchargement&lt;/strong&gt;&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Pour installer Pandoc à partir de la page de téléchargement, procédez comme suit :&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;olist arabic&quot;&gt;
&lt;ol class=&quot;arabic&quot;&gt;
&lt;li&gt;
&lt;p&gt;Accédez à la page de téléchargement de Pandoc : &lt;a href=&quot;https://pandoc.org/installing.html/&quot;&gt;https://pandoc.org/installing.html&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Téléchargez l&amp;#8217;installateur de package pour votre système d&amp;#8217;exploitation.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Exécutez l&amp;#8217;installateur pour installer Pandoc.&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;&lt;strong&gt;Installation à partir d&amp;#8217;un fichier zip&lt;/strong&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Pour installer Pandoc à partir d&amp;#8217;un fichier zip, procédez comme suit :&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;olist arabic&quot;&gt;
&lt;ol class=&quot;arabic&quot;&gt;
&lt;li&gt;
&lt;p&gt;Téléchargez le fichier zip contenant les binaires de Pandoc et la documentation.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Décompressez le fichier zip.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Déplacez les binaires vers un répertoire de votre choix.&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;&lt;strong&gt;Installation à l&amp;#8217;aide de Chocolatey&lt;/strong&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Pour installer Pandoc à l&amp;#8217;aide de Chocolatey, procédez comme suit :&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;olist arabic&quot;&gt;
&lt;ol class=&quot;arabic&quot;&gt;
&lt;li&gt;
&lt;p&gt;Ouvrez une invite de commande.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Exécutez la commande suivante :&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-powershell&quot; data-lang=&quot;powershell&quot;&gt;choco install pandoc&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;&lt;strong&gt;Installation à l&amp;#8217;aide de winget&lt;/strong&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Pour installer Pandoc à l&amp;#8217;aide de winget, procédez comme suit :&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;olist arabic&quot;&gt;
&lt;ol class=&quot;arabic&quot;&gt;
&lt;li&gt;
&lt;p&gt;Ouvrez une invite de commande.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Exécutez la commande suivante :&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-powershell&quot; data-lang=&quot;powershell&quot;&gt;winget install --source winget --exact --id JohnMacFarlane.Pandoc&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;&lt;strong&gt;Recommandations&lt;/strong&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Par défaut, Pandoc crée des PDFs à l&amp;#8217;aide de LaTeX.
Il est recommandé d&amp;#8217;installer LaTeX via MiKTeX.
Avec l&amp;#8217;option &lt;code&gt;--pdf-engine&lt;/code&gt;, vous pouvez toutefois spécifier d&amp;#8217;autres programmes pour cette tâche.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;&lt;strong&gt;Mise en garde&lt;/strong&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;L&amp;#8217;utilisation de plusieurs méthodes d&amp;#8217;installation peut entraîner deux installations distinctes de Pandoc.
Il est recommandé de désinstaller correctement Pandoc avant de passer à une méthode d&amp;#8217;installation alternative.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;&lt;strong&gt;Installation sur linux par WSL&lt;/strong&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Vérifiez si la version de pandoc dans votre gestionnaire de paquets n&amp;#8217;est pas obsolète.
Pandoc se trouve dans les dépôts de Debian, Ubuntu, Slackware, Arch, Fedora, NixOS, openSUSE, gentoo et Void.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Pour obtenir la dernière version, nous proposons un paquet binaire pour l&amp;#8217;architecture amd64 sur la page de téléchargement.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;L&amp;#8217;exécutable est lié statiquement et n&amp;#8217;a pas de dépendances dynamiques ni de dépendances sur des fichiers de données externes.
Remarque : en raison du lien statique, le binaire pandoc de ce paquet ne peut pas utiliser les filtres lua qui nécessitent des modules lua externes écrits en C.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Un tarball et un installateur deb sont fournis.
Pour installer le deb :&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-bash&quot; data-lang=&quot;bash&quot;&gt;sudo dpkg -i $DEB&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Exemple au moment de l&amp;#8217;écriture :&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-bash&quot; data-lang=&quot;bash&quot;&gt;wget https://github.com/jgm/pandoc/releases/download/3.1.11.1/pandoc-3.1.11.1-1-amd64.deb&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-bash&quot; data-lang=&quot;bash&quot;&gt;sudo dpkg -i pandoc-3.1.11.1-1-amd64.deb&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;où &lt;code&gt;$DEB&lt;/code&gt; est le chemin vers le deb téléchargé.
Cela installera l&amp;#8217;exécutable &lt;code&gt;pandoc&lt;/code&gt; et la page de manuel.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Si vous utilisez une distribution basée sur RPM, vous pourrez peut-être installer le deb de notre page de téléchargement à l&amp;#8217;aide d&amp;#8217;alien.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Sur n&amp;#8217;importe quelle distribution, vous pouvez installer à partir du tarball dans &lt;code&gt;$DEST&lt;/code&gt; (par exemple, &lt;code&gt;/usr/local/&lt;/code&gt; ou &lt;code&gt;$HOME/.local&lt;/code&gt;) en faisant :&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-bash&quot; data-lang=&quot;bash&quot;&gt;tar xvzf $TGZ --strip-components 1 -C $DEST&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;où &lt;code&gt;$TGZ&lt;/code&gt; est le chemin vers le tarball zippé téléchargé.
Pour les versions de Pandoc antérieures à 2.0, qui ne fournissent pas de tarball, essayez plutôt :&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-bash&quot; data-lang=&quot;bash&quot;&gt;ar p $DEB data.tar.gz | tar xvz --strip-components 2 -C $DEST&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Vous pouvez également installer à partir de la source, en utilisant les instructions ci-dessous sous &lt;code&gt;Compilation à partir de la source&lt;/code&gt;.
Notez que la plupart des distributions ont la plate-forme Haskell dans leurs dépôts de paquets.
Par exemple, sur Debian/Ubuntu, vous pouvez l&amp;#8217;installer avec &lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-bash&quot; data-lang=&quot;bash&quot;&gt;apt-get install haskell-platform&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Par défaut, Pandoc crée des PDFs à l&amp;#8217;aide de LaTeX.
Nous vous recommandons d&amp;#8217;installer TeX Live via votre gestionnaire de paquets.
(Sur Debian/Ubuntu, &lt;code&gt;apt-get install texlive&lt;/code&gt;).
Avec l&amp;#8217;option &lt;code&gt;--pdf-engine&lt;/code&gt;, vous pouvez toutefois spécifier d&amp;#8217;autres programmes pour cette tâche.&lt;/p&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;

&lt;div id=&quot;preamble&quot;&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;div class=&quot;title&quot;&gt;&lt;em&gt;Temps de lecture : 2 min&lt;/em&gt;&lt;/div&gt;
&lt;p&gt;Créer une implémentation complète de la classe kotlin.Triple en JavaScript, TypeScript et Python en utilisant la programmation fonctionnelle.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;&lt;strong&gt;Note :&lt;/strong&gt; Les types &lt;code&gt;Maybe&lt;/code&gt;, &lt;code&gt;Either&lt;/code&gt;, &lt;code&gt;Result&lt;/code&gt; ne font pas partie du langage de base en JavaScript ou TypeScript, donc il faut les implémenter nous-mêmes.&lt;/p&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_javascript&quot;&gt;JavaScript&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-javascript&quot; data-lang=&quot;javascript&quot;&gt;//javascript
// Maybe type
const Maybe = (value) =&amp;gt; ({
  map: (fn) =&amp;gt; (value !== null &amp;amp;&amp;amp; value !== undefined ? Maybe(fn(value)) : Maybe(null)),
  flatMap: (fn) =&amp;gt; (value !== null &amp;amp;&amp;amp; value !== undefined ? fn(value) : Maybe(null)),
  getOrElse: (defaultValue) =&amp;gt; (value !== null &amp;amp;&amp;amp; value !== undefined ? value : defaultValue),
});

// Either type
const Either = {
  Left: (value) =&amp;gt; ({
    map: (fn) =&amp;gt; Either.Left(value),
    flatMap: (fn) =&amp;gt; Either.Left(value),
    getOrElse: (defaultValue) =&amp;gt; defaultValue,
    isLeft: true,
    isRight: false,
  }),
  Right: (value) =&amp;gt; ({
    map: (fn) =&amp;gt; Either.Right(fn(value)),
    flatMap: (fn) =&amp;gt; fn(value),
    getOrElse: (defaultValue) =&amp;gt; value,
    isLeft: false,
    isRight: true,
  }),
};

// Triple class
class Triple {
  constructor(a, b, c) {
    this.a = a;
    this.b = b;
    this.c = c;
  }

  map(fn) {
    return new Triple(fn(this.a), fn(this.b), fn(this.c));
  }

  static of(a, b, c) {
    return new Triple(a, b, c);
  }

  // Example method using Maybe and Either
  divideBy(other) {
    return Maybe(this.b)
      .flatMap((numerator) =&amp;gt;
        Maybe(other)
          .flatMap((denominator) =&amp;gt;
            denominator !== 0
              ? Either.Right(numerator / denominator)
              : Either.Left(&#39;Division by zero&#39;)
          )
      )
      .getOrElse(Either.Left(&#39;Invalid input&#39;));
  }
}

// Example usage
const triple = Triple.of(1, 2, 3);
const result = triple.map((x) =&amp;gt; x * 2);
console.log(result); // Triple { a: 2, b: 4, c: 6 }

const divisionResult = triple.divideBy(2);
console.log(divisionResult); // Either.Right { value: 1 }

const invalidDivisionResult = triple.divideBy(0);
console.log(invalidDivisionResult); // Either.Left { value: &#39;Division by zero&#39; }&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_typescript&quot;&gt;TypeScript&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-typescript&quot; data-lang=&quot;typescript&quot;&gt;//Typescript
// Maybe type
// noinspection JSAnnotator

type Maybe&amp;lt;T&amp;gt; = {
  map&amp;lt;U&amp;gt;(fn: (value: T) =&amp;gt; U): Maybe&amp;lt;U&amp;gt;;
  flatMap&amp;lt;U&amp;gt;(fn: (value: T) =&amp;gt; Maybe&amp;lt;U&amp;gt;): Maybe&amp;lt;U&amp;gt;;
  getOrElse(defaultValue: T): T;
};

const just = &amp;lt;T&amp;gt;(value: T): Maybe&amp;lt;T&amp;gt; =&amp;gt; ({
  map: &amp;lt;U&amp;gt;(fn: (value: T) =&amp;gt; U) =&amp;gt; just(fn(value)),
  flatMap: &amp;lt;U&amp;gt;(fn: (value: T) =&amp;gt; Maybe&amp;lt;U&amp;gt;) =&amp;gt; fn(value),
  getOrElse: (_: T) =&amp;gt; value,
});

const nothing = &amp;lt;T&amp;gt;(): Maybe&amp;lt;T&amp;gt; =&amp;gt; ({
  map: &amp;lt;U&amp;gt;(_: (value: T) =&amp;gt; U) =&amp;gt; nothing&amp;lt;U&amp;gt;(),
  flatMap: &amp;lt;U&amp;gt;(_: (value: T) =&amp;gt; Maybe&amp;lt;U&amp;gt;) =&amp;gt; nothing&amp;lt;U&amp;gt;(),
  getOrElse: (defaultValue: T) =&amp;gt; defaultValue,
});

// Either type
type Either&amp;lt;L, R&amp;gt; = {
  map&amp;lt;U&amp;gt;(fn: (value: R) =&amp;gt; U): Either&amp;lt;L, U&amp;gt;;
  flatMap&amp;lt;U&amp;gt;(fn: (value: R) =&amp;gt; Either&amp;lt;L, U&amp;gt;): Either&amp;lt;L, U&amp;gt;;
  getOrElse(defaultValue: R): R;
  isLeft: boolean;
  isRight: boolean;
};

const left = &amp;lt;L, R&amp;gt;(value: L): Either&amp;lt;L, R&amp;gt; =&amp;gt; ({
  map: &amp;lt;U&amp;gt;(_: (value: R) =&amp;gt; U) =&amp;gt; left&amp;lt;L, U&amp;gt;(value),
  flatMap: &amp;lt;U&amp;gt;(_: (value: R) =&amp;gt; Either&amp;lt;L, U&amp;gt;) =&amp;gt; left&amp;lt;L, U&amp;gt;(value),
  getOrElse: (defaultValue: R) =&amp;gt; defaultValue,
  isLeft: true,
  isRight: false,
});

const right = &amp;lt;L, R&amp;gt;(value: R): Either&amp;lt;L, R&amp;gt; =&amp;gt; ({
  map: &amp;lt;U&amp;gt;(fn: (value: R) =&amp;gt; U) =&amp;gt; right&amp;lt;L, U&amp;gt;(fn(value)),
  flatMap: &amp;lt;U&amp;gt;(fn: (value: R) =&amp;gt; Either&amp;lt;L, U&amp;gt;) =&amp;gt; fn(value),
  getOrElse: (_: R) =&amp;gt; value,
  isLeft: false,
  isRight: true,
});

// Triple class
class Triple&amp;lt;T&amp;gt; {
  constructor(public a: T, public b: T, public c: T) {}

  map&amp;lt;U&amp;gt;(fn: (value: T) =&amp;gt; U): Triple&amp;lt;U&amp;gt; {
    return new Triple&amp;lt;U&amp;gt;(fn(this.a), fn(this.b), fn(this.c));
  }

  static of&amp;lt;T&amp;gt;(a: T, b: T, c: T): Triple&amp;lt;T&amp;gt; {
    return new Triple&amp;lt;T&amp;gt;(a, b, c);
  }

  // Example method using Maybe and Either
  divideBy(other: T): Either&amp;lt;string, number&amp;gt; {
    return just(this.b)
      .flatMap((numerator) =&amp;gt;
        just(other)
          .flatMap((denominator) =&amp;gt;
            denominator !== 0 ? right(numerator / denominator) : left(&#39;Division by zero&#39;)
          )
      )
      .getOrElse(left(&#39;Invalid input&#39;));
  }
}

// Example usage
const triple = Triple.of(1, 2, 3);
const result = triple.map((x) =&amp;gt; x * 2);
console.log(result); // Triple { a: 2, b: 4, c: 6 }

const divisionResult = triple.divideBy(2);
console.log(divisionResult); // Either.Right { value: 1 }

const invalidDivisionResult = triple.divideBy(0);
console.log(invalidDivisionResult); // Either.Left { value: &#39;Division by zero&#39; }&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_python_pydantic_pymonad&quot;&gt;Python, pydantic, pymonad&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Pour créer une implémentation en Python en utilisant &lt;code&gt;pydantic&lt;/code&gt; pour la validation des types et &lt;code&gt;pymonad&lt;/code&gt; pour les monades :&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;title&quot;&gt;Installer les dépendances :&lt;/div&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-bash&quot; data-lang=&quot;bash&quot;&gt;pip install pydantic pymonad&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-python&quot; data-lang=&quot;python&quot;&gt;from pymonad.either import Either, Left, Right
from pydantic import BaseModel, ValidationError, validator

# Définition de la classe Triple avec Pydantic
class Triple(BaseModel):
    a: int
    b: int
    c: int

    @validator(&#39;b&#39;)
    def validate_b(cls, b, values):
        if b == 0:
            raise ValueError(&#39;Division by zero is not allowed&#39;)
        return b

    # Méthode utilisant Either pour la gestion des erreurs
    def divide_by(self, other):
        def division(numerator, denominator):
            return Right(numerator / denominator)

        def handle_error(error):
            return Left(str(error))

        return Either(lambda: division(self.b, other)).or_else(handle_error)

# Exemple d&#39;utilisation
try:
    triple = Triple(a=1, b=2, c=3)
    result = triple.divide_by(2)

    if result.is_right:
        print(f&#39;Division result: {result.value}&#39;)
    else:
        print(f&#39;Error: {result.value}&#39;)

except ValidationError as e:
    print(f&#39;Validation Error: {e}&#39;)
except Exception as e:
    print(f&#39;An unexpected error occurred: {e}&#39;)&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;ulist&quot;&gt;
&lt;div class=&quot;title&quot;&gt;Dans cet exemple :&lt;/div&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;pydantic&lt;/code&gt; pour définir la classe &lt;code&gt;Triple&lt;/code&gt; avec des champs typés.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;La méthode &lt;code&gt;divide_by&lt;/code&gt; utilise la monade &lt;code&gt;Either&lt;/code&gt; de &lt;code&gt;pymonad&lt;/code&gt; pour gérer les erreurs potentielles résultant de la division par zéro.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Validation personnalisée pour s&amp;#8217;assurer que la valeur de &lt;code&gt;b&lt;/code&gt; n&amp;#8217;est pas égale à zéro. Si elle est égale à zéro, une exception est levée, et &lt;code&gt;pymonad&lt;/code&gt; capture cette exception pour renvoyer un résultat &lt;code&gt;Left&lt;/code&gt; indiquant l&amp;#8217;erreur.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;

&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_table_des_matières&quot;&gt;Table des Matières&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;&lt;em&gt;temps de lecture : 30 min&lt;/em&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;ulist&quot;&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;a href=&quot;#_introduction&quot;&gt;Introduction&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;a href=&quot;#_structure_de_base_en_google_apps_script&quot;&gt;Structure de base en Google Apps Script&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;a href=&quot;#_types_et_variables_en_google_apps_script&quot;&gt;Types et Variables en Google Apps Script&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;a href=&quot;#Constantes&quot;&gt;Variables, et Lettres en Google Apps Script&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;a href=&quot;#_opérations_et_opérateurs_en_google_apps_script&quot;&gt;Opérations et Opérateurs en Google Apps Script&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;a href=&quot;#Var&quot;&gt;Let et Const en Google Apps Script&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;a href=&quot;#_structures_de_contrôle_en_google_apps_script&quot;&gt;Structures de Contrôle en Google Apps Script&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;a href=&quot;#_boucles_en_google_apps_script&quot;&gt;Boucles en Google Apps Script&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;a href=&quot;#_objets_en_google_apps_script&quot;&gt;Objets en Google Apps Script&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;a href=&quot;#_fonctions_en_google_apps_script&quot;&gt;Fonctions en Google Apps Script&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;a href=&quot;#_paramètres_et_scopes_en_google_apps_script&quot;&gt;Paramètres et Scopes en Google Apps Script&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;a href=&quot;#_opérateurs_de_repos_et_de_propagation_en_google_apps_script&quot;&gt;Opérateurs de Repos et de Propagation en Google Apps Script&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;a href=&quot;#_affectation_par_décomposition_en_google_apps_script&quot;&gt;Affectation par Décomposition en Google Apps Script&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;a href=&quot;#_collections_et_programmation_déclarative_en_google_apps_script&quot;&gt;Collections et Programmation Déclarative en Google Apps Script&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_introduction&quot;&gt;Introduction&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Google Apps Script (GAS) est une plateforme de développement de scripts associée à divers services Google tels que Google Sheets, Google Docs et Google Forms. Elle permet d&amp;#8217;automatiser des tâches, d&amp;#8217;ajouter des fonctionnalités personnalisées et d&amp;#8217;intégrer des services Google.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Dans ce mémo, nous allons explorer les principaux concepts de Google Apps Script en nous appuyant sur des exemples concrets. Nous aborderons des notions telles que les variables, les boucles, les fonctions, et bien d&amp;#8217;autres, en les adaptant au contexte spécifique de GAS.&lt;/p&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_structure_de_base_en_google_apps_script&quot;&gt;Structure de base en Google Apps Script&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Pour commencer, examinons la structure de base d&amp;#8217;un script Google Apps.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-javascript&quot; data-lang=&quot;javascript&quot;&gt;/**
 * Structure de base en Google Apps Script
 */
function exempleStructureGAS() {
    // Votre code ici
    Logger.log(&quot;Hello, Google Apps Script!&quot;);
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_types_et_variables_en_google_apps_script&quot;&gt;Types et Variables en Google Apps Script&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Google Apps Script utilise JavaScript en tant que langage de programmation. Les types de données et les variables fonctionnent de manière similaire à JavaScript standard.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-javascript&quot; data-lang=&quot;javascript&quot;&gt;/**
 * Types et Variables en Google Apps Script
 */
function exempleTypesVariablesGAS() {
    // Votre code ici
    var nombre = 42;
    var texte = &quot;Bonjour, Google Apps Script!&quot;;
    Logger.log(nombre);
    Logger.log(texte);
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_opérations_et_opérateurs_en_google_apps_script&quot;&gt;Opérations et Opérateurs en Google Apps Script&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Les opérations et opérateurs en Google Apps Script sont les mêmes qu&amp;#8217;en JavaScript.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-javascript&quot; data-lang=&quot;javascript&quot;&gt;/**
 * Opérations et Opérateurs en Google Apps Script
 */
function exempleOperationsGAS() {
    // Votre code ici
    var x = 10;
    var y = 5;
    var resultat = x + y;
    Logger.log(resultat);
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_var_let_et_const_en_google_apps_script&quot;&gt;Var, Let et Const en Google Apps Script&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;En GAS, les concepts de &lt;code&gt;var&lt;/code&gt;, &lt;code&gt;let&lt;/code&gt;, et &lt;code&gt;const&lt;/code&gt; sont utilisés pour déclarer des variables. Cependant, il est essentiel de comprendre leurs différences et leurs implications.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-javascript&quot; data-lang=&quot;javascript&quot;&gt;/**
 * Var, Let et Const en Google Apps Script
 */
function exempleVarLetConstGAS() {
    // Votre code ici
    // Utilisation de var
    var x = 10;
    if (true) {
        var x = 20; // La variable x est modifiée globalement
    }
    Logger.log(x);

    // Utilisation de let
    let y = 30;
    if (true) {
        let y = 40; // La variable y est limitée au bloc if
    }
    Logger.log(y);

    // Utilisation de const
    const z = 50;
    // z = 60; // Impossible de réassigner une constante
    Logger.log(z);
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_structures_de_contrôle_en_google_apps_script&quot;&gt;Structures de Contrôle en Google Apps Script&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Les structures de contrôle telles que &lt;code&gt;if&lt;/code&gt;, &lt;code&gt;else&lt;/code&gt;, &lt;code&gt;while&lt;/code&gt; et &lt;code&gt;for&lt;/code&gt; sont utilisées pour gérer le flux d&amp;#8217;exécution dans Google Apps Script.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-javascript&quot; data-lang=&quot;javascript&quot;&gt;/**
 * Structures de Contrôle en Google Apps Script
 */
function exempleStructuresControleGAS() {
    // Votre code ici
    var condition = true;

    if (condition) {
        Logger.log(&quot;La condition est vraie.&quot;);
    } else {
        Logger.log(&quot;La condition est fausse.&quot;);
    }

    var compteur = 0;
    while (compteur &amp;lt; 5) {
        Logger.log(compteur);
        compteur++;
    }

    for (var i = 0; i &amp;lt; 3; i++) {
        Logger.log(i);
    }
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_paramètres_et_scopes_en_google_apps_script&quot;&gt;Paramètres et Scopes en Google Apps Script&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Les paramètres et les scopes jouent un rôle crucial dans le développement de scripts en GAS. Comprenez comment ils fonctionnent pour éviter des comportements inattendus.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-javascript&quot; data-lang=&quot;javascript&quot;&gt;/**
 * Paramètres et Scopes en Google Apps Script
 */
function exempleParametresScopesGAS(parametre) {
    // Votre code ici
    var variableGlobale = &quot;Je suis global&quot;;

    function afficherParametre() {
        Logger.log(parametre);
    }

    afficherParametre();
    Logger.log(variableGlobale);
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_constantes_variables_et_lettres_en_google_apps_script&quot;&gt;Constantes, Variables, et Lettres en Google Apps Script&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Comprendre la différence entre &lt;code&gt;const&lt;/code&gt;, &lt;code&gt;var&lt;/code&gt;, et &lt;code&gt;let&lt;/code&gt; est essentiel pour une utilisation efficace des variables en Google Apps Script.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-javascript&quot; data-lang=&quot;javascript&quot;&gt;/**
 * Constantes, Variables, et Lettres en Google Apps Script
 */
function exempleConstantesVariablesLettresGAS() {
    // Votre code ici
    const constante = &quot;Je ne change pas&quot;;
    Logger.log(constante);

    var variable = &quot;Je peux changer&quot;;
    Logger.log(variable);

    let lettre = &quot;Je peux aussi changer, mais seulement dans mon bloc&quot;;
    Logger.log(lettre);
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_boucles_en_google_apps_script&quot;&gt;Boucles en Google Apps Script&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Les boucles, telles que &lt;code&gt;for&lt;/code&gt; et &lt;code&gt;while&lt;/code&gt;, sont essentielles pour itérer sur des éléments et effectuer des opérations répétitives.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-javascript&quot; data-lang=&quot;javascript&quot;&gt;/**
 * Boucles en Google Apps Script
 */
function exempleBouclesGAS() {
    // Votre code ici
    for (var i = 0; i &amp;lt; 3; i++) {
        Logger.log(i);
    }

    var condition = true;
    var compteur = 0;

    while (condition) {
        Logger.log(&quot;Tour de boucle&quot;);
        compteur++;
        if (compteur === 3) {
            condition = false;
        }
    }
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_objets_en_google_apps_script&quot;&gt;Objets en Google Apps Script&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Les objets sont utilisés pour structurer les données. Dans GAS, de nombreux objets intégrés facilitent l&amp;#8217;interaction avec les services Google.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-javascript&quot; data-lang=&quot;javascript&quot;&gt;/**
 * Objets en Google Apps Script
 */
function exempleObjetsGAS() {
    // Votre code ici
    var feuille = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
    var cellule = feuille.getRange(&quot;A1&quot;);
    cellule.setValue(&quot;Nouvelle valeur&quot;);
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_constantes_variables_et_lettres_en_google_apps_script_2&quot;&gt;Constantes, Variables, et Lettres en Google Apps Script&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Comprendre la différence entre &lt;code&gt;const&lt;/code&gt;, &lt;code&gt;var&lt;/code&gt;, et &lt;code&gt;let&lt;/code&gt; est essentiel pour une utilisation efficace des variables en Google Apps Script.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-javascript&quot; data-lang=&quot;javascript&quot;&gt;/**
 * Constantes, Variables, et Lettres en Google Apps Script
 */
function exempleConstantesVariablesLettresGAS() {
    // Votre code ici
    const constante = &quot;Je ne change pas&quot;;
    Logger.log(constante);

    var variable = &quot;Je peux changer&quot;;
    Logger.log(variable);

    let lettre = &quot;Je peux aussi changer, mais seulement dans mon bloc&quot;;
    Logger.log(lettre);
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_fonctions_en_google_apps_script&quot;&gt;Fonctions en Google Apps Script&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Les fonctions sont des éléments fondamentaux en programmation. En GAS, elles peuvent être déclarées et appelées de différentes manières.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-javascript&quot; data-lang=&quot;javascript&quot;&gt;/**
 * Fonctions en Google Apps Script
 */
function exempleFonctionsGAS() {
    // Votre code ici
    function additionner(a, b) {
        return a + b;
    }

    var resultat = additionner(2, 3);
    Logger.log(resultat);

    // Fonction anonyme
    var multiplier = function (x, y) {
        return x * y;
    };

    Logger.log(multiplier(4, 5));
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_opérateurs_de_repos_et_de_propagation_en_google_apps_script&quot;&gt;Opérateurs de Repos et de Propagation en Google Apps Script&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Les opérateurs de repos (&lt;code&gt;&amp;#8230;&amp;#8203;&lt;/code&gt;) et de propagation (&lt;code&gt;&amp;#8230;&amp;#8203;&lt;/code&gt;) sont utiles pour manipuler les tableaux et les objets de manière concise.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-javascript&quot; data-lang=&quot;javascript&quot;&gt;/**
 * Opérateurs de Repos et de Propagation en Google Apps Script
 */
function exempleOperateursReposPropagationGAS() {
    // Votre code ici
    // Opérateur de repos (...) pour les tableaux
    var nombres = [1, 2, 3, 4, 5];
    var [...copieNombres] = nombres;
    Logger.log(copieNombres);

    // Opérateur de propagation (...) pour les objets
    var objOriginal = { x: 1, y: 2 };
    var objClone = { ...objOriginal, z: 3 };
    Logger.log(objClone);
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_affectation_par_décomposition_en_google_apps_script&quot;&gt;Affectation par Décomposition en Google Apps Script&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;L&amp;#8217;affectation par décomposition est une fonctionnalité puissante qui permet d&amp;#8217;extraire des valeurs d&amp;#8217;objets et de tableaux de manière concise.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-javascript&quot; data-lang=&quot;javascript&quot;&gt;/**
 * Affectation par Décomposition en Google Apps Script
 */
function exempleAffectationDecompositionGAS() {
    // Votre code ici
    var coordonnees = [3, 4];
    var [x, y] = coordonnees;
    Logger.log(x);
    Logger.log(y);

    var utilisateur = { nom: &quot;John&quot;, age: 30 };
    var { nom, age } = utilisateur;
    Logger.log(nom);
    Logger.log(age);
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_collections_et_programmation_déclarative_en_google_apps_script&quot;&gt;Collections et Programmation Déclarative en Google Apps Script&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Google Apps Script prend en charge les structures de données telles que les tableaux, et les concepts de programmation fonctionnelle et d&amp;#8217;itération déclarative (&amp;gt;&amp;lt;impérative), tels que &lt;code&gt;map&lt;/code&gt;, &lt;code&gt;reduce&lt;/code&gt; et &lt;code&gt;forEach&lt;/code&gt;.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-javascript&quot; data-lang=&quot;javascript&quot;&gt;/**
 * Collections et Programmation Déclarative en Google Apps Script
 */
function exempleCollectionsFonctionnelleGAS() {
    // Votre code ici
    // Exemple de tableau (collection)
    var nombres = [1, 2, 3, 4, 5];

    // Utilisation de forEach
    nombres.forEach(function (nombre) {
        Logger.log(nombre);
    });

    // Utilisation de map
    var carresNombres = nombres.map(function (nombre) {
        return nombre * nombre;
    });
    Logger.log(carresNombres);

    // Utilisation de reduce
    var somme = nombres.reduce(function (acc, nombre) {
        return acc + nombre;
    }, 0);
    Logger.log(somme);
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_conclusion&quot;&gt;Conclusion&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Ce mémo a couvert les concepts fondamentaux de Google Apps Script en les illustrant à l&amp;#8217;aide d&amp;#8217;exemples de code concrets. Utilisez ces connaissances pour automatiser vos tâches quotidiennes, personnaliser vos documents et exploiter pleinement les fonctionnalités de Google Apps Script.&lt;/p&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;

&lt;div id=&quot;preamble&quot;&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Durée : 30 minutes&lt;/p&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
