&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-css&quot; data-lang=&quot;css&quot;&gt;@import url(&quot;https://fonts.googleapis.com/css2?family=Oswald:wght@500&amp;amp;display=swap&quot;);

@font-face {
  font-family: &quot;DMSerif&quot;;
