&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;début_conclusion&quot;&gt;Débug &amp;amp; Conclusion&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-css&quot; data-lang=&quot;css&quot;&gt;/* all elements:
supprime les comportements par défaut*/
* {
