&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_afficher_laide&quot;&gt;1. Afficher l&amp;#8217;aide&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-bash&quot; data-lang=&quot;bash&quot;&gt;./gradlew --help&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_définir_la_propriété_système_de_la_jvm_d_system_prop&quot;&gt;2. Définir la propriété système de la JVM : &lt;code&gt;-D, --system-prop&lt;/code&gt;&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-bash&quot; data-lang=&quot;bash&quot;&gt;./gradlew -Dmyprop=myvalue
#ou
./gradlew --system-prop myvalue&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_définir_la_propriété_du_projet_pour_le_build_script_pmypropmyvalue&quot;&gt;3. Définir la propriété du projet pour le build script : &lt;code&gt;-Pmyprop=myvalue&lt;/code&gt;&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-bash&quot; data-lang=&quot;bash&quot;&gt;./gradlew -Pmyprop=myvalue
#ou
./gradlew --project-prop myvalue&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_spécifie_le_répertoire_de_démarrage_de_gradle_la_valeur_par_défaut_est_le_répertoire_actuel&quot;&gt;4. Spécifie le répertoire de démarrage de Gradle. La valeur par défaut est le répertoire actuel.&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-bash&quot; data-lang=&quot;bash&quot;&gt;./gradlew -p ~/src/next_startup
#ou
./gradlew --project-dir ~/src/next_startup&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_surcharger_la_property_param_component_par_la_ligne_de_commande&quot;&gt;5. Surcharger la property &#39;param_component&#39; par la ligne de commande :&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-bash&quot; data-lang=&quot;bash&quot;&gt;./gradlew -Pparam_component=CUSTOM_VALUE&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_ajouter_un_dossier_à_un_source_set_dans_un_projet_normal_avec_le_kotlin_dsl&quot;&gt;6. Ajouter un dossier à un source-set dans un projet normal avec le kotlin dsl&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-kotlin&quot; data-lang=&quot;kotlin&quot;&gt;sourceSets {
    getByName(&quot;test&quot;){
        java.srcDir(&quot;src/scripts/groovy&quot;)
    }
    getByName(&quot;test&quot;){
        java.srcDir(&quot;src/scripts/kscript&quot;)
    }
    getByName(&quot;test&quot;){
        java.srcDir(&quot;src/test/javascript&quot;)
    }
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_ajouter_un_dossier_à_un_source_set_dans_un_projet_android_avec_le_groovy_dsl&quot;&gt;7. Ajouter un dossier à un source-set dans un projet android avec le groovy dsl&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-kotlin&quot; data-lang=&quot;kotlin&quot;&gt;android {
    sourceSets {
        main.java.srcDirs += &quot;src/main/../../../../ceelo/domain/src/main/java/&quot;
        test.java.srcDirs += &quot;src/test/../../../../ceelo/domain/src/test/java/&quot;
    }
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_éviter_de_construire_et_tester_un_sous_module&quot;&gt;8. Éviter de construire et tester un sous module&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;gradle build -x :excluded-module:check -x :excluded-module:assemble -x :excluded-module:build&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;title&quot;&gt;Déplacer des fichiers&lt;/div&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-kotlin&quot; data-lang=&quot;kotlin&quot;&gt;tasks.register(&quot;moveWebappNode&quot;) {
    doLast {
        ant.withGroovyBuilder {
            &quot;move&quot;(
                &quot;webapp/node_modules&quot; to &quot;$rootDir/webapp-src/node_modules&quot;,
            )
        }
    }
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_tar_un_dossier&quot;&gt;9. Tar un dossier&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-kotlin&quot; data-lang=&quot;kotlin&quot;&gt;tasks.register&amp;lt;Tar&amp;gt;(&quot;tarWebapp&quot;) {
    dependsOn(&quot;moveWebappNpm&quot;)
    group = WEBAPP
    description = &quot;tar webapp&quot;
    doLast {
        setOf(
            &quot;build&quot;,
            &quot;target&quot;,
            &quot;node_modules&quot;
        ).forEach { dir -&amp;gt; exclude { it.name .dir } }
        archiveFileName.set(&quot;webapp.tar&quot;)
        destinationDirectory.set(File(&quot;${rootDir.absolutePath}$sep$WEBAPP_SRC&quot;))
    }
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_afficher_les_dépendances_dun_build&quot;&gt;10. Afficher les dépendances d&amp;#8217;un build&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-kotlin&quot; data-lang=&quot;kotlin&quot;&gt;tasks.register(&quot;printDependencies&quot;) {
    description = &quot;print project dependencies&quot;
    group = WEBAPP
    doLast {
        println(&quot;${project.name} dependencies&quot;)
        mutableMapOf&amp;lt;String, Map&amp;lt;String, String&amp;gt;&amp;gt;(
            &quot;buildDependencies&quot; to buildDependencies,
            &quot;domainDeps&quot; to domainDeps,
            &quot;domainTestDeps&quot; to domainTestDeps,
        ).apply { putAll(appModules) }
            .forEach { module -&amp;gt;
                if (module.value.isNotEmpty()) {
                    println(&quot;${module.key}:&quot;)
                    module.value.forEach { println(dependency(it)) }
                    println()
                }
            }
    }
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_exemple_dutilisation_de_reduce_concaténation_dune_list_dans_un_string&quot;&gt;11. Exemple d&amp;#8217;utilisation de reduce : concaténation d&amp;#8217;une list dans un string&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-kotlin&quot; data-lang=&quot;kotlin&quot;&gt;tasks.register(&quot;printWebappSrc&quot;) {
    description = &quot;print webapp sources&quot;
    group = WEBAPP
    doLast {
        webAppSrc
            .reduce { acc, s -&amp;gt; &quot;$acc\n\t$s&quot; }
            .run { println(&quot;$WEBAPP_SRC: $this\n&quot;) }
    }
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_récupérer_la_description_dune_tache_en_particulier&quot;&gt;12. Récupérer la description d&amp;#8217;une tache en particulier&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-bash&quot; data-lang=&quot;bash&quot;&gt;./gradlew -q help --task foo&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_pour_lancer_une_tache_depuis_le_workingdir_root_alors_préfixer_la_tache_pas_un&quot;&gt;13. Pour lancer une tache depuis le workingDir root, alors préfixer la tache pas un &lt;code&gt;:&lt;/code&gt;&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-bash&quot; data-lang=&quot;bash&quot;&gt;./gradlew :foo&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_pour_relancer_les_taches_qui_ont_échouées_utiliser_loption_rerun_tasks&quot;&gt;14. Pour relancer les taches qui ont échouées, utiliser l&amp;#8217;option &lt;code&gt;--rerun-tasks&lt;/code&gt;&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-bash&quot; data-lang=&quot;bash&quot;&gt;./gradlew check --rerun-tasks&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_lancer_une_tâche_dans_un_projet_spécifique_depuis_un_autre_répertoire&quot;&gt;15. Lancer une tâche dans un projet spécifique depuis un autre répertoire&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;L&amp;#8217;option &lt;code&gt;-p&lt;/code&gt; (ou &lt;code&gt;--project-dir&lt;/code&gt;) permet de spécifier le chemin d&amp;#8217;accès à un projet Gradle et d&amp;#8217;y exécuter une tâche, même si le répertoire courant est différent.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Par exemple, pour lancer la tâche &lt;code&gt;build&lt;/code&gt; du projet situé dans &lt;code&gt;~/projets/mon-autre-projet&lt;/code&gt; tout en étant dans un autre répertoire :&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-bash&quot; data-lang=&quot;bash&quot;&gt;./gradlew -p ~/projets/mon-autre-projet build&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Cela est particulièrement utile pour scripter des actions sur plusieurs projets depuis un emplacement central.&lt;/p&gt;
&lt;/div&gt;
&lt;hr&gt;
&lt;div class=&quot;ulist&quot;&gt;
&lt;div class=&quot;title&quot;&gt;voir aussi :&lt;/div&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;a href=&quot;https://docs.gradle.org/current/userguide/command_line_interface.html#sec:command_line_warnings&quot;&gt;ref&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;a href=&quot;https://docs.gradle.org/current/userguide/command_line_interface.html#sec:command_line_options&quot;&gt;ref&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;a href=&quot;https://stackoverflow.com/a/36178581/837404&quot;&gt;discussion&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;

&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;les sealed classes, ne sont pas des énumérations(mot clef:enum).&lt;br&gt;
Venant de Java, vous pourriez être tenté de surcharger votre énumération d&amp;#8217;apport de fonctionnalités:&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-java&quot; data-lang=&quot;java&quot;&gt;enum PizzaOrderStatus {
    ORDER_RECEIVED,
    PIZZA_BEING_MADE,
    OUT_FOR_DELIVERY,
    COMPLETED;
    public PizzaOrderStatus nextStatus() {
        switch (this) {
        case ORDER_RECEIVED: return PIZZA_BEING_MADE;
        case PIZZA_BEING_MADE: return OUT_FOR_DELIVERY;
        case OUT_FOR_DELIVERY: return COMPLETED;
        case COMPLETED:return COMPLETED;
        }
    }
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Au lieu de cela, vous pouvez utiliser la sealed classe :&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-kotlin&quot; data-lang=&quot;kotlin&quot;&gt;sealed class PizzaOrderStatus(protected val orderId: Int) {
    abstract fun nextStatus() : PizzaOrderStatus
    class OrderReceived(orderId: Int) : PizzaOrderStatus(orderId) {
        override fun nextStatus(): PizzaOrderStatus {
            return PizzaBeingMade(orderId)
        }
    }
    class PizzaBeingMade(orderId: Int) : PizzaOrderStatus(orderId) {
        override fun nextStatus(): PizzaOrderStatus {
            return OutForDelivery(orderId)
        }
    }
    class OutForDelivery(orderId: Int) : PizzaOrderStatus(orderId) {
        override fun nextStatus(): PizzaOrderStatus {
            return Completed(orderId)
        }
    }
    class Completed(orderId: Int) : PizzaOrderStatus(orderId) {
        override fun nextStatus(): PizzaOrderStatus {
            return this
        }
    }
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;L&amp;#8217;avantage de cette approche est que nous pouvons maintenant transmettre des données avec le
statut:&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-kotlin&quot; data-lang=&quot;kotlin&quot;&gt;var status: PizzaOrderStatus = OrderReceived(123)
while (status !is Completed) {
    status = when (status) {
        is OrderReceived -&amp;gt; status.nextStatus()
        is PizzaBeingMade -&amp;gt; status.nextStatus()
        is OutForDelivery -&amp;gt; status.nextStatus()
        is Completed -&amp;gt; status
    }
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;En général, les sealed classes sont bonnes si vous voulez avoir des données associées à un
Etat.&lt;/p&gt;
&lt;/div&gt;

