&lt;span class=&quot;image&quot;&gt;&lt;img src=&quot;../../img/0036_training_kotlin_post/colls-coreInterfaces.gif&quot; alt=&quot;Collections&quot;&gt;&lt;/span&gt;&lt;br&gt;&lt;/p&gt;
