&lt;div class=&quot;sect2&quot;&gt;
&lt;h3 id=&quot;_basiques_fonctionnels&quot;&gt;Basiques fonctionnels&lt;/h3&gt;
&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_declarative_x_imperative_approach&quot;&gt;Declarative X imperative approach&lt;/h4&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-kotlin&quot; data-lang=&quot;kotlin&quot;&gt;package functional

import kotlin.test.Test
import kotlin.test.assertEquals

class DeclarativeTests {
    val input = listOf(
        &quot;123&quot;, &quot;abc&quot;, &quot;1ds&quot;, &quot;987&quot;, &quot;abdf&quot;, &quot;1d3&quot;, &quot;de1&quot;, &quot;88&quot;, &quot;101&quot;
    )

    fun imperativeSum(list: List&amp;lt;String&amp;gt;): Int {
        var sum = 0
        for (item in list) {
            try {
                sum += item.toInt()
            } catch (_: NumberFormatException) {
            }
        }
        return sum
    }

    @Test
    fun `test imperative approach`() {
        imperativeSum(input).run {
            println(&quot;Sum $this&quot;)
            assertEquals(1299, this)
        }
    }

    fun isValidNumber(s: String) = try {
        s.toInt()
        true
    } catch (_: NumberFormatException) {
        false
    }

    fun declarativeSum(list: List&amp;lt;String&amp;gt;) = list
        .filter(::isValidNumber)
        .map(String::toInt)
        .sum()

    @Test
    fun `test declarative approach`() {
        assertEquals(1299, declarativeSum(input).apply {
            println(&quot;Sum $this&quot;)
        })
    }
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_exercice_1_1&quot;&gt;Exercice 1.1&lt;/h4&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Implémenter la fonction sumInRange, qui additionne les valeurs dans&lt;br&gt;
une List&amp;lt;String&amp;gt; dans un intervalle donné. La signature est :&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-kotlin&quot; data-lang=&quot;kotlin&quot;&gt;fun sumInRange(input: List&amp;lt;String&amp;gt;, range: IntRange): Int&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-kotlin&quot; data-lang=&quot;kotlin&quot;&gt;@Test
fun `Exercise 1_1`() {
    assertEquals(4, sumInRange(
        listOf(&quot;1&quot;, &quot;10&quot;, &quot;a&quot;, &quot;7&quot;, &quot;ad2&quot;, &quot;3&quot;),
            1..5
        ).apply { println(&quot;sumInRange 1..5: $this&quot;) }
    )
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Essayez-le et vérifiez votre réponse avec la &lt;a href=&quot;https://github.com/cheroliv/cheroliv.com/blob/master/codes/src/test/kotlin/functional/DeclarativeTests.kt&quot;&gt;solution&lt;/a&gt;.&lt;/p&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_higher_order_functions&quot;&gt;Higher-order functions&lt;/h4&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-kotlin&quot; data-lang=&quot;kotlin&quot;&gt;package functional

import java.io.ByteArrayOutputStream
import java.io.PrintStream
import java.lang.System.*
import java.lang.Thread.sleep
import kotlin.math.sign
import kotlin.test.Test
import kotlin.test.assertEquals

class BasicsHOFTests {
    val ONE_SECOND = 1000L

    @Test
    fun `high order function`() {
        //capture de la sortie standard
        val standardOut: PrintStream? = out
        val outputStreamCaptor = ByteArrayOutputStream()
        setOut(PrintStream(outputStreamCaptor))

        3.times { println(&quot;Hello&quot;) }
        assertEquals(
            buildString {
                repeat(3) { append(&quot;Hello\n&quot;) }
                deleteAt(length - 1)
            }, outputStreamCaptor
                .toString()
                .trim()
        )

        //libération de la sortie standard
        setOut(standardOut)
    }

    fun Int.times1(fn: () -&amp;gt; Unit) {
        for (i in 1..this) {
            fn()
        }
    }

    fun Int.times2(fn: () -&amp;gt; Unit) {
        for (i in 1..this) fn()
    }

    fun Int.times3(fn: () -&amp;gt; Unit) =
        (1..this).forEach { fn() }


    fun Int.times4(fn: () -&amp;gt; Unit) =
        repeat((1..this).count()) { fn() }

    fun Int.times(fn: () -&amp;gt; Unit) =
        (1..this).forEach { _ -&amp;gt; fn() }
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_exercice_1_2&quot;&gt;Exercice 1.2&lt;/h4&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Implémenter chrono, qui accepte une fonction de type &lt;code&gt;() &amp;#8594;&lt;/code&gt;&lt;br&gt;
Unit en entrée et renvoie le temps passé à l&amp;#8217;exécuter. La signature est :&lt;br&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-kotlin&quot; data-lang=&quot;kotlin&quot;&gt;fun chrono(fn : () -&amp;gt; Unité) : Long&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-kotlin&quot; data-lang=&quot;kotlin&quot;&gt;@Test
fun `Exercise 1_2`() {
    val waitOneSec = { sleep(ONE_SECOND) }
    chrono(waitOneSec).apply {
        println(&quot;chrono: $this&quot;)
        assertEquals(1, sign)
    }
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Essayez-le et vérifiez votre réponse avec la &lt;a href=&quot;https://github.com/cheroliv/cheroliv.com/blob/master/codes/src/test/kotlin/functional/BasicsHOFTests.kt&quot;&gt;solution&lt;/a&gt;.&lt;/p&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_composition&quot;&gt;Composition&lt;/h4&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-kotlin&quot; data-lang=&quot;kotlin&quot;&gt;package functional

import kotlin.test.Test
import kotlin.test.assertEquals


fun double(x: Int): Int = 2 * x
fun square(x: Int): Int = x * x
fun squareAndDouble1(x: Int) = double(square(x))

infix fun &amp;lt;A, B, C&amp;gt; ((A) -&amp;gt; B).compose(g: (B) -&amp;gt; C)
        : (A) -&amp;gt; C = { a -&amp;gt; g(this(a)) }

class CompositionTests {
    @Test
    fun composition_impure() {
        assertEquals(200, double(square(10)))
        assertEquals(200, squareAndDouble1(10))
    }

    @Test
    fun composition_pure() {
        val squareAndDouble = ::square compose ::double
        assertEquals(200, squareAndDouble(10))
    }

}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_pure_functions_and_testability&quot;&gt;Pure functions and testability&lt;/h4&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-kotlin&quot; data-lang=&quot;kotlin&quot;&gt;package functional

import java.io.ByteArrayOutputStream
import java.io.PrintStream
import java.lang.System.out
import java.lang.System.setOut
import kotlin.test.Test
import kotlin.test.assertEquals


var count = 0

//impure car une variable global subit un effet de bord
fun impure(value: Int): Int {
    count++
    return value + count
}

//impure car utilisation de la sortie standard qui fait muter le system
fun addOneAndLog(x: Int): Int {
    val result = x + 1
    println(&quot;New Value is $result&quot;)
    return result
}

//pure
fun addOne(x: Int) = (x + 1).run {
    Pair(this, &quot;New Value is $this&quot;)
}

class PureTests {
    @Test
    fun `impure fonction`() {
        assertEquals(3, impure(2))

        val standardOut = out
        val outputStreamCaptor = ByteArrayOutputStream()
        setOut(PrintStream(outputStreamCaptor))

        addOneAndLog(3)

        assertEquals(
            &quot;New Value is 4&quot;,
            outputStreamCaptor
                .toString()
                .trim()
        )
        setOut(standardOut)
    }

    @Test
    fun `pure fonction`() {
        addOne(3).run {
            assertEquals(4, first)
            assertEquals(&quot;New Value is 4&quot;, second)
        }
    }
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_exception_handling&quot;&gt;Exception handling&lt;/h4&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-kotlin&quot; data-lang=&quot;kotlin&quot;&gt;package functional

import org.junit.jupiter.api.assertThrows
import kotlin.Result.Companion.failure
import kotlin.Result.Companion.success
import kotlin.test.Test
import kotlin.test.assertEquals

//NumberFormatException est un effet de bord qui rend la fonction impure
fun strToInt(str: String) = str.toInt()

//pure
fun strToIntOrNull(str: String) = try {
    str.toInt()
} catch (nfe: NumberFormatException) {
    null
}

//pure avec gestion de l&#39;exception plus élégante
fun strToIntResult(str: String): Result&amp;lt;Int&amp;gt; =
    try {
        success(str.toInt())
    } catch (nfe: NumberFormatException) {
        failure(nfe)
    }

class ExceptionHandlingTests {
    @Test
    fun impure() {
        assertThrows&amp;lt;NumberFormatException&amp;gt; { strToInt(&quot;foo&quot;) }
        assertEquals(1, strToInt(&quot;1&quot;))
    }

    @Test
    fun pure() {
        assertEquals(null, strToIntOrNull(&quot;foo&quot;))
        assertEquals(1, strToIntOrNull(&quot;1&quot;))
    }

    @Test
    fun `pure avec result`() {
        assertEquals(1, strToIntResult(&quot;1&quot;).getOrNull())
        assertEquals(
            &quot;For input string: \&quot;foo\&quot;&quot;,
            strToIntResult(&quot;foo&quot;)
                .exceptionOrNull()
                ?.message
        )
    }
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect2&quot;&gt;
&lt;h3 id=&quot;_points_clés&quot;&gt;Points clés&lt;/h3&gt;
&lt;div class=&quot;ulist&quot;&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;Alors que la programmation orientée objet signifie programmer avec des objets,
la programmation fonctionnelle signifie programmer avec des fonctions.
Vous décomposez un problème en plusieurs sous-problèmes, que vous modélisez avec
les fonctions.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Les fonctions d&amp;#8217;ordre supérieur acceptent d&amp;#8217;autres fonctions en entrée ou renvoient d&amp;#8217;autres
fonctionnent comme des valeurs de retour.
La théorie des catégories est la théorie de la composition, et vous l&amp;#8217;utilisez pour comprendre
comment composer vos fonctions dans un programme de travail.
La valeur de sortie d&amp;#8217;une fonction pure ne dépend que de ses paramètres d&amp;#8217;entrée, et elle
n&amp;#8217;a pas d&amp;#8217;effets secondaires.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Un effet secondaire est quelque chose qu&amp;#8217;une fonction fait au monde extérieur. Ce
peut être un journal dans la sortie standard ou la modification de la valeur d&amp;#8217;une variable globale.
La programmation fonctionnelle fonctionne pour les fonctions pures, mais elle fournit également les
des outils pour transformer des fonctions impures en fonctions pures.
Vous pouvez rendre une fonction impure pure en déplaçant les effets pour les rendre
partie de la valeur de retour.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;La programmation fonctionnelle est une question de composition.
La gestion des erreurs est un cas typique d&amp;#8217;effets secondaires, et Kotlin vous donne les outils
pour les gérer de manière fonctionnelle.&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect2&quot;&gt;
&lt;h3 id=&quot;_approfondir_java8_lambdas_expressions_et_interface_fonctionnelles&quot;&gt;Approfondir java8: lambdas expressions et interface fonctionnelles&lt;/h3&gt;
