&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_installation_du_paquet_microk8s&quot;&gt;Installation du paquet microk8s:&lt;/h4&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;sudo snap install microk8s --classic --channel=1.19&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_ajout_de_lutilisateur_courrant_au_group_du_processus_microk8s&quot;&gt;Ajout de l&amp;#8217;utilisateur courrant au group du processus microk8s&lt;/h4&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;sudo usermod -a -G microk8s $USER
sudo chown -f -R $USER ~/.kube
su - $USER&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_afficher_létat_de_microk8s&quot;&gt;Afficher l&amp;#8217;état de microk8s&lt;/h4&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;microk8s status --wait-ready&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_acceder_à_kubernetes&quot;&gt;Acceder à Kubernetes&lt;/h4&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Récuperer les nodes(noeuds):&lt;br&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;microk8s kubectl get nodes&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Récuperer les services en cours:&lt;br&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;microk8s kubectl get services&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Récuperer les pods en cours:&lt;br&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;microk8s kubectl get pods&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_ajouter_un_alias_à_son_shell&quot;&gt;Ajouter un alias à son shell&lt;/h4&gt;
&lt;div class=&quot;sect4&quot;&gt;
&lt;h5 id=&quot;_pour_zsh&quot;&gt;pour zsh&lt;/h5&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;touch ~/.zsh_alias;
echo &quot;alias kubectl=&#39;microk8s kubectl&#39;&quot; &amp;gt;&amp;gt; ~/.zsh_alias;&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect4&quot;&gt;
&lt;h5 id=&quot;_pour_bash&quot;&gt;pour bash&lt;/h5&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;touch ~/.bash_alias;
echo &quot;alias kubectl=&#39;microk8s kubectl&#39;&quot; &amp;gt;&amp;gt; ~/.bash_alias;&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_installer_des_add_ons&quot;&gt;Installer des add-ons&lt;/h4&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Pour commencer, il est recommandé d&amp;#8217;ajouter la gestion DNS pour faciliter la communication entre les services. Pour les applications nécessitant du stockage, le module complémentaire «stockage» fournit un espace de répertoire sur l&amp;#8217;hôte. Ceux-ci sont faciles à configurer:&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;microk8s enable dns storage&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_démarrer_et_arreter_microk8s&quot;&gt;Démarrer et arreter MicroK8s&lt;/h4&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;microk8s stop&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;microk8s start&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Notez que si vous laissez MicroK8 en marche, il redémarrera automatiquement après un redémarrage. Si vous ne voulez pas que cela se produise, n&amp;#8217;oubliez pas de lancer l&amp;#8217;arrêt microk8s avant de l&amp;#8217;éteindre.&lt;/p&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_deployer_une_app&quot;&gt;Deployer une app&lt;/h4&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;microk8s kubectl create deployment nginx --image=nginx&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Pour vérifier l&amp;#8217;état du déploiement:&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;microk8s kubectl get pods&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;

&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_gradle_kotlin_dsl&quot;&gt;Gradle-Kotlin-DSL:&lt;/h4&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;open class PrintHerokuVersion : Exec() {
    init {
        this.workingDir = project.rootDir
        this.commandLine(&quot;/snap/bin/heroku&quot;, &quot;-v&quot;)
        this.standardOutput = ByteArrayOutputStream()
    }
}

project.tasks.register&amp;lt;PrintHerokuVersion&amp;gt;(&quot;printHerokuVersion&quot;)

project.tasks.withType&amp;lt;PrintHerokuVersion&amp;gt; {
    doLast { logger.info(standardOutput.toString()) }
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Pour exécuter la tâche:&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;$ ./gradlew pHV&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_gradle_groovy_dsl&quot;&gt;Gradle-Groovy-DSL:&lt;/h4&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;task printHerokuVersionGroovy(type: Exec) {
    workingDir(project.projectDir)
    commandLine(&quot;/snap/bin/heroku&quot;, &quot;-v&quot;)
    standardOutput = new ByteArrayOutputStream()
    doLast {
        logger.info(standardOutput.toString())
    }
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Pour exécuter la tâche:&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;$ ./gradlew pHVG&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;

&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;NotImplementedException NotImplementedError, utilité pour les tests, ça permet de savoir, où on en est, et la cause du fail.&lt;br&gt;
Pas encore implémenté, permet de lever la bonne exception.&lt;br&gt;
Il y a :&lt;br&gt;
&lt;a href=&quot;http://commons.apache.org/proper/commons-lang/javadocs/api-release/org/apache/commons/lang3/NotImplementedException.html&quot;&gt;org.apache.commons.lang3.NotImplementedException&lt;/a&gt;&lt;br&gt;
&lt;a href=&quot;https://kotlinlang.org/api/latest/jvm/stdlib/kotlin/-not-implemented-error/&quot;&gt;kotlin.NotImplementedError&lt;/a&gt;&lt;br&gt;&lt;/p&gt;
&lt;/div&gt;

&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_liens_interserver_net&quot;&gt;Liens: &lt;a href=&quot;https://www.interserver.net/tips/kb/extract-tar-gz-files-using-linux-command-line/&quot;&gt;interserver.net&lt;/a&gt;&lt;/h4&gt;

&lt;/div&gt;

&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;ajouter l’argument --rerun-tasks à la ligne commande.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;$ ./gradlew test --rerun-tasks&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;

&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_source_hackernoon_com&quot;&gt;source: &lt;a href=&quot;https://hackernoon.com/dont-install-postgres-docker-pull-postgres-bee20e200198&quot;&gt;hackernoon.com&lt;/a&gt;&lt;/h4&gt;

&lt;/div&gt;

&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-json&quot; data-lang=&quot;json&quot;&gt;{&quot;fr&quot;: {
    &quot;and&quot;: [
      &quot;* &quot;,
      &quot;Et que &quot;,
      &quot;Et qu&#39;&quot;,
      &quot;Et &quot;
    ],
    &quot;background&quot;: [
      &quot;Contexte&quot;
    ],
    &quot;but&quot;: [
      &quot;* &quot;,
      &quot;Mais que &quot;,
      &quot;Mais qu&#39;&quot;,
      &quot;Mais &quot;
    ],
    &quot;examples&quot;: [
      &quot;Exemples&quot;
    ],
    &quot;feature&quot;: [
      &quot;Fonctionnalité&quot;
    ],
    &quot;given&quot;: [
      &quot;* &quot;,
      &quot;Soit &quot;,
      &quot;Sachant que &quot;,
      &quot;Sachant qu&#39;&quot;,
      &quot;Sachant &quot;,
      &quot;Etant donné que &quot;,
      &quot;Etant donné qu&#39;&quot;,
      &quot;Etant donné &quot;,
      &quot;Etant donnée &quot;,
      &quot;Etant donnés &quot;,
      &quot;Etant données &quot;,
      &quot;Étant donné que &quot;,
      &quot;Étant donné qu&#39;&quot;,
      &quot;Étant donné &quot;,
      &quot;Étant donnée &quot;,
      &quot;Étant donnés &quot;,
      &quot;Étant données &quot;
    ],
    &quot;name&quot;: &quot;French&quot;,
    &quot;native&quot;: &quot;français&quot;,
    &quot;rule&quot;: [
      &quot;Règle&quot;
    ],
    &quot;scenario&quot;: [
