&lt;/div&gt;
&lt;/div&gt;

&lt;div class=&quot;sect4&quot;&gt;
&lt;h5 id=&quot;_surcharger_un_parametre_par_la_ligne_de_commande&quot;&gt;Surcharger un parametre par la ligne de commande :&lt;/h5&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;$ ./gradlew -Pparam_component=CUSTOM&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;

&lt;div class=&quot;sect1&quot;&gt;
&lt;h2 id=&quot;_changer_de_depot_distant_dans_git&quot;&gt;Changer de depot distant dans git&lt;/h2&gt;
&lt;div class=&quot;sectionbody&quot;&gt;
&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_sources&quot;&gt;Sources:&lt;/h4&gt;
&lt;div class=&quot;ulist&quot;&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;a href=&quot;https://xenovation.com/blog/source-control-management/git/how-to-change-remote-git-repository&quot;&gt;xenovation&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;a href=&quot;https://intellipaat.com/community/3102/git-show-remote-url-how-can-i-determine-the-url-that-a-local-git-repository-was-originally-cloned-from&quot;&gt;intellipaat&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_changer_de_repo_distant_dans_git&quot;&gt;changer de repo distant dans git&lt;/h4&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;afficher l&amp;#8217;url du repo distant courrant:&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;git config --get remote.origin.url&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Pour plus d&amp;#8217;information sur le depot distant:&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;git remote show origin&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Lister les depots distants&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;git remote -v&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Changer de dépot distants&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;git remote set-url origin git@github.com:kotlin-codes/hands-on-design-pattern-kotlin.git&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Ajouter quand le dépot n’existe pas&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;git remote add origin git@github.com:kotlin-codes/foo.git&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Pusher&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;git push -u origin master&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;ou&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;git push -u origin main&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;&lt;em&gt;changement d&amp;#8217;adresse ip&lt;/em&gt;&lt;br&gt;
relancer la commande suivante pour que les pushs passent.&lt;br&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;git remote set-url origin git@github.com:USER_ACCOUNT/PROJECT.git&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;

&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_liens_stackoverflow&quot;&gt;Liens: &lt;a href=&quot;https://stackoverflow.com/a/1078539/837404&quot;&gt;stackoverflow&lt;/a&gt;&lt;/h4&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;$ wget -r -k -np http://site.com/docs/manual/&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Pour définir un dossier cible ajouter l’argument -P puis donner le chemin.&lt;/p&gt;
&lt;/div&gt;
&lt;/div&gt;

&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_liens_etcher&quot;&gt;Liens: &lt;a href=&quot;https://www.balena.io/etcher/&quot;&gt;etcher&lt;/a&gt;&lt;/h4&gt;

&lt;/div&gt;

&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_liens_askubuntu&quot;&gt;Liens: &lt;a href=&quot;https://askubuntu.com/questions/86849/how-to-unzip-a-zip-file-from-the-terminal&quot;&gt;askubuntu&lt;/a&gt;&lt;/h4&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Si vous souhaitez extraire vers un dossier de destination particulier, vous pouvez utiliser :&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;$ unzip fichier.zip -d dossier_destination&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Si les répertoires source et de destination sont identiques, vous pouvez simplement faire:&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;$ unzip file.zip&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;

&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_liens_stackexchange&quot;&gt;Liens: &lt;a href=&quot;https://unix.stackexchange.com/questions/72661/show-sum-of-file-sizes-in-directory-listing&quot;&gt;stackexchange&lt;/a&gt;&lt;/h4&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code&gt;$ du -ach --exclude &quot;./.*&quot; /home/troll/&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;

&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_détruire_une_branch_sur_github&quot;&gt;Détruire une branch sur github&lt;/h4&gt;

&lt;/div&gt;
&lt;div class=&quot;sect3&quot;&gt;
&lt;h4 id=&quot;_lien_gist&quot;&gt;Lien: &lt;a href=&quot;https://gist.github.com/cheroliv/921a13ed23ae6d4d66af8d43dd536987&quot;&gt;gist&lt;/a&gt;&lt;/h4&gt;

&lt;/div&gt;

&lt;div class=&quot;paragraph&quot;&gt;
&lt;div class=&quot;title&quot;&gt;Pourquoi asciidoc ou markdown ?&lt;/div&gt;
&lt;p&gt;Ici, je m’oriente vers asciidoc, car j’ai déjà quelques tickets écris en asciidoc.&lt;br&gt;
Asciidoc est un langage de balisage, qui permet de produire du contenu, en apportant une mise en page qui garde le texte lisible pour un humain.&lt;br&gt;
C’est une façon de standardiser les traitements de textes pour des contenus simples sans logiciel supplémentaire.&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;ulist&quot;&gt;
&lt;div class=&quot;title&quot;&gt;Liens :&lt;/div&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;a href=&quot;https://blog.oxiane.com/2018/06/13/asciidoc-documentation-as-code/&quot; target=&quot;_blank&quot; rel=&quot;noopener&quot;&gt;@jmdoudoux sur blog.oxiane.com&lt;/a&gt; [asciidoc]&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;a href=&quot;https://powerman.name/doc/asciidoc&quot; target=&quot;_blank&quot; rel=&quot;noopener&quot;&gt;powerman.name&lt;/a&gt; [asciidoc]&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;div class=&quot;title&quot;&gt;asciidoc:&lt;/div&gt;
&lt;p&gt;&lt;a href=&quot;https://docs.asciidoctor.org/asciidoc/latest/attributes/character-replacement-ref/&quot; target=&quot;_blank&quot; rel=&quot;noopener&quot;&gt;character-replacement-ref&lt;/a&gt;&lt;/p&gt;
&lt;/div&gt;

&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Pour installer un paquet debian depuis un fichier .deb en ligne de commandes.&lt;br&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-bash&quot; data-lang=&quot;bash&quot;&gt;$ sudo dpkg -i /chemin/du/fichier/deb/&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;voir içi pour la &lt;a href=&quot;https://unix.stackexchange.com/questions/159094/how-to-install-a-deb-file-by-dpkg-i-or-by-apt&quot;&gt;référence&lt;/a&gt;&lt;br&gt;&lt;/p&gt;
&lt;/div&gt;

&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Dans un projet applicatif piloté par le gestionnaire de build Gradle&lt;br&gt;
il est plus agréable d’avoir la visibilité sur tous les dossiers&lt;br&gt;
participant au développement de l’application,&lt;br&gt;
comme des dossiers de ressources qui ne sont pas&lt;br&gt;
dans les chemins par convention.&lt;br&gt;
Par exemple je veux que le dossier src/jbake,&lt;br&gt;
soit visible en tant ‘resource folder’,&lt;br&gt;
il est possible de le faire en rentrant dans la configuration du projet,&lt;br&gt;
dans les wizards de l’IDE.
Cependant cette option n’est pas sauvegardée au rechargement suivant&lt;br&gt;
du projet Gradle dans l’IDE. Pour apporter cette configuration de façon permanente&lt;br&gt;
la solution est de surcharger la configuration des chemins de sources&lt;br&gt;
dans le fichier de configuration build.gradle tel que aux lignes 18, 19, 20 et 21 :&lt;br&gt;
build.gradle&lt;br&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-groovy&quot; data-lang=&quot;groovy&quot;&gt;plugins {
    id &quot;java&quot;
    id &quot;groovy&quot;
    id &quot;org.jbake.site&quot; version &quot;5.0.0&quot;
    id &quot;org.ajoberstar.git-publish&quot; version &quot;2.1.1&quot;
}
repositories {
    mavenCentral()
    jcenter()
}
group project_group
version project_version
sourceSets {
    main {
        java { srcDirs = [] }
        groovy { srcDirs =[&quot;src/main/java&quot;, &quot;src/main/groovy&quot;] }
        resources {
            srcDirs =[
                    &quot;src/main/resources&quot;,
                    &quot;src/jbake&quot;//in order to get site src content in the IDE
            ]
        }
    }
    test {
        java { srcDirs = [] }
        groovy { srcDirs =[&quot;src/test/java&quot;, &quot;src/test/groovy&quot;] }
    }
}
test {
    useJUnitPlatform()
}
configurations {
    ivy
}
dependencies {
    ivy &quot;org.apache.ivy:ivy:$ivy_version&quot;
    implementation &quot;org.codehaus.groovy:groovy-all:$groovy_version&quot;
    implementation &quot;org.asciidoctor:asciidoctor-java-integration:$asciidoctor_java_integration_version&quot;
    implementation &quot;org.freemarker:freemarker:$freemarker_version&quot;
    testImplementation &quot;org.junit.jupiter:junit-jupiter-api:$junit5_version&quot;
    testRuntimeOnly &quot;org.junit.jupiter:junit-jupiter-engine:$junit5_version&quot;
}
gitPublish {
    repoUri = github_pages_blog_repository
    branch = git_branch
    contents {
        from(file(jbake_content_from)) {
            into jbake_content_to
        }
    }
}
tasks.withType(GroovyCompile) {
    groovyClasspath += configurations.ivy
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;

&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Le sujet du ticket est la configuration d&amp;#8217;un script de build Gradle.&lt;br&gt;
Je veux pouvoir utiliser un script Groovy sans faire référence&lt;br&gt;
au projet Gradle dans lequel je l&amp;#8217;ai attaché.&lt;br&gt;
Je veux avoir la possibilité de lancer ce script Groovy hors de Gradle&lt;br&gt;
sans que les annotations ivy de récupération de dépendance externe&lt;br&gt;
ne viennent poser problème de performance ou de compilation&lt;br&gt;
du script de build Gradle.&lt;br&gt;
Pour illustrer la configuration je m&amp;#8217;appuie sur deux scripts:&lt;br&gt;
un script de build Gradle et un script Groovy.&lt;br&gt;
Le script Groovy contient au début à la ligne 2,&lt;br&gt;
une instruction pour tirer une dépendance  externe&lt;br&gt;
à l&amp;#8217;aide du gestionnaire de dépendance ivy.&lt;br&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-Groovy&quot; data-lang=&quot;Groovy&quot;&gt;#!/usr/bin/env groovy
@Grab(&quot;commons-io:commons-io:2.6&quot;)

import org.apache.commons.io.FileUtils

static String getSeparator() {
    System.getProperty(&quot;file.separator&quot;)
}

String from = &quot;${System.getProperty(&quot;user.home&quot;)}${separator}.config${separator}transmission${separator}torrents&quot;
String to = &quot;${System.getProperty(&quot;user.home&quot;)}${separator}Documents${separator}torrents_completed&quot;

File fromDlDir = new File(&quot;${System.getProperty(&quot;user.home&quot;)}${separator}Téléchargements&quot;)
File fromDir = new File(from)
File toDir = new File(to)

Collection&amp;lt;File&amp;gt; torrentFiles = FileUtils.listFiles(
        fromDir,
        [&quot;torrent&quot;] as String[],
        false)
torrentFiles.addAll(FileUtils.listFiles(
        fromDlDir,
        [&quot;torrent&quot;, &quot;torrent.added&quot;] as String[],
        false))


torrentFiles.empty ?: torrentFiles.each { it -&amp;gt;
    FileUtils.copyFileToDirectory(it, toDir)
}
println torrentFiles.size()&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;Dans le fichier build.gradle, maintenant voyons comment mettre en harmonie&lt;br&gt;
les deux gestionnaires de dépendances, ivy et Gradle.
L&amp;#8217;accord entre les deux se fait aux lignes :&lt;br&gt;
26, 30, 37, 38 et 39&lt;br&gt;
Ainsi je peux lancer mon script Groovy manuellement,&lt;br&gt;
et la compilation de Gradle n&amp;#8217;est pas gênée par le @Grab.&lt;br&gt;
Les dépendances du script Groovy ne sont pas à fournir dans Gradle.&lt;br&gt;
Par contre je ne peux pas lancer le script Groovy depuis Gradle.&lt;br&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-Groovy&quot; data-lang=&quot;Groovy&quot;&gt;plugins {
    id &quot;java&quot;
    id &quot;groovy&quot;
}

repositories {
    mavenCentral()
    jcenter()
}

sourceSets {
    main {
        java { srcDirs = [] }
        groovy { srcDirs =[&quot;src/main/java&quot;, &quot;src/main/groovy&quot;] }
        resources {
            srcDirs =[&quot;src/main/resources&quot;]
        }
    }
    test {
        java { srcDirs = [] }
        groovy { srcDirs =[&quot;src/test/java&quot;, &quot;src/test/groovy&quot;] }
    }
}

configurations {
    ivy
}

dependencies {
    ivy &quot;org.apache.ivy:ivy:$ivy_version&quot;
    implementation &quot;org.codehaus.groovy:groovy-all:$groovy_version&quot;
}



tasks.withType(GroovyCompile) {
    groovyClasspath += configurations.ivy
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;référence du ticket  sur &lt;a href=&quot;https://stackoverflow.com/a/18174033/837404&quot;&gt;stackoverflow&lt;/a&gt;&lt;/p&gt;
&lt;/div&gt;

&lt;div class=&quot;sect2&quot;&gt;
&lt;h3 id=&quot;_le_pgcd&quot;&gt;Le PGCD&lt;/h3&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;&lt;a href=&quot;https://fr.wikipedia.org/wiki/Plus_grand_commun_diviseur&quot;&gt;wiki PGCD ou Plus Grand Commun Diviseur&lt;/a&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;sect2&quot;&gt;
&lt;h3 id=&quot;_le_ppmc&quot;&gt;Le PPMC&lt;/h3&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;&lt;a href=&quot;https://fr.wikipedia.org/wiki/Plus_petit_commun_multiple&quot;&gt;wiki PPMC ou Plus Petit Commun Multiple&lt;/a&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;AlgebraUtils.groovy&lt;br&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre class=&quot;highlight&quot;&gt;&lt;code class=&quot;language-groovy&quot; data-lang=&quot;groovy&quot;&gt;package com.cheroliv.misc

import groovy.transform.CompileStatic

@CompileStatic
class AlgebraUtils {

    /**
     * Great common divisor
     * Plus grand commun diviseur(pgcd)
     * Great Common Divisor
     * @param a
     * @param b
     * @return
     */
    static Integer gcd(Integer a, Integer b) {
        !b ? a : gcd(b, a % b)
    }


    /**
     * Least common multiple
     * Plus petit commun multiplicateur(ppmc)
     * @param a
     * @param b
     * @return
     */
    static BigInteger lcm(Integer a, Integer b) {
        (a * b / gcd(a, b)) as BigInteger
    }

    static void main(String... args) {
        Integer a = 96
        Integer b = 28
        println &quot;gcd($a, $b) = ${gcd(a, b)}&quot;
        a = 790
        b = 990
        println &quot;lcm($a, $b) = ${lcm(a, b)}&quot;
    }
}&lt;/code&gt;&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;div class=&quot;paragraph&quot;&gt;
&lt;p&gt;résultat:&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&quot;listingblock&quot;&gt;
&lt;div class=&quot;content&quot;&gt;
&lt;pre&gt;gcd(96, 28) = 4
lcm(790, 990) = 78210&lt;/pre&gt;
&lt;/div&gt;
&lt;/div&gt;
&lt;/div&gt;

&lt;div class=&quot;paragraph&quot;&gt;
